const E2EE_PRIVATE_JWK_STORAGE_KEY = 'of_e2ee_private_jwk'
const E2EE_PUBLIC_KEY_STORAGE_KEY = 'of_e2ee_public_key'
const E2EE_VERSION = 'ecdh-p256-aesgcm-v1'

function toBase64(data: ArrayBuffer): string {
  const bytes = new Uint8Array(data)
  let binary = ''
  for (let i = 0; i < bytes.length; i++) binary += String.fromCharCode(bytes[i])
  return btoa(binary)
}

function fromBase64(value: string): ArrayBuffer {
  const binary = atob(value)
  const bytes = new Uint8Array(binary.length)
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i)
  return bytes.buffer
}

async function importPeerPublicKey(publicKeyB64: string): Promise<CryptoKey> {
  return await crypto.subtle.importKey(
    'raw',
    fromBase64(publicKeyB64),
    { name: 'ECDH', namedCurve: 'P-256' },
    false,
    [],
  )
}

export function useE2EE() {
  const auth = useAuthStore()
  const config = useRuntimeConfig()

  async function ensureLocalKeyPair() {
    if (!import.meta.client) throw new Error('E2EE is only available in browser')

    const savedPrivate = localStorage.getItem(E2EE_PRIVATE_JWK_STORAGE_KEY)
    const savedPublic = localStorage.getItem(E2EE_PUBLIC_KEY_STORAGE_KEY)

    if (savedPrivate && savedPublic) {
      const privateKey = await crypto.subtle.importKey(
        'jwk',
        JSON.parse(savedPrivate),
        { name: 'ECDH', namedCurve: 'P-256' },
        true,
        ['deriveBits'],
      )
      return { privateKey, publicKeyB64: savedPublic }
    }

    const pair = await crypto.subtle.generateKey(
      { name: 'ECDH', namedCurve: 'P-256' },
      true,
      ['deriveBits'],
    )

    const privateJwk = await crypto.subtle.exportKey('jwk', pair.privateKey)
    const publicRaw = await crypto.subtle.exportKey('raw', pair.publicKey)
    const publicKeyB64 = toBase64(publicRaw)

    localStorage.setItem(E2EE_PRIVATE_JWK_STORAGE_KEY, JSON.stringify(privateJwk))
    localStorage.setItem(E2EE_PUBLIC_KEY_STORAGE_KEY, publicKeyB64)

    return { privateKey: pair.privateKey, publicKeyB64 }
  }

  async function deriveChatKey(peerPublicKeyB64: string, chatId: string): Promise<CryptoKey> {
    const { privateKey } = await ensureLocalKeyPair()
    const peerPublicKey = await importPeerPublicKey(peerPublicKeyB64)

    const sharedBits = await crypto.subtle.deriveBits(
      { name: 'ECDH', public: peerPublicKey },
      privateKey,
      256,
    )

    const keyMaterial = await crypto.subtle.importKey(
      'raw',
      sharedBits,
      'HKDF',
      false,
      ['deriveKey'],
    )

    const enc = new TextEncoder()
    return await crypto.subtle.deriveKey(
      {
        name: 'HKDF',
        hash: 'SHA-256',
        salt: enc.encode(chatId),
        info: enc.encode('openfamily-e2ee-v1'),
      },
      keyMaterial,
      { name: 'AES-GCM', length: 256 },
      false,
      ['encrypt', 'decrypt'],
    )
  }

  async function ensurePublished() {
    if (!import.meta.client || !auth.token) return

    const headers = useAuthHeaders()
    const { publicKeyB64 } = await ensureLocalKeyPair()

    if (auth.user?.e2ee_public_key === publicKeyB64) return

    await $fetch(`${config.public.apiBase}/users/me/e2ee-key`, {
      method: 'PUT',
      headers,
      body: { public_key: publicKeyB64 },
    })

    if (auth.user) {
      auth.user.e2ee_public_key = publicKeyB64
      localStorage.setItem('of_user', JSON.stringify(auth.user))
    }
  }

  async function encryptTextForChat(plaintext: string, peerPublicKeyB64: string, chatId: string) {
    const key = await deriveChatKey(peerPublicKeyB64, chatId)
    const nonce = crypto.getRandomValues(new Uint8Array(12))
    const data = new TextEncoder().encode(plaintext)
    const cipher = await crypto.subtle.encrypt({ name: 'AES-GCM', iv: nonce }, key, data)

    return {
      ciphertext: toBase64(cipher),
      nonce: toBase64(nonce.buffer),
      version: E2EE_VERSION,
    }
  }

  async function decryptTextForChat(ciphertextB64: string, nonceB64: string, peerPublicKeyB64: string, chatId: string) {
    const key = await deriveChatKey(peerPublicKeyB64, chatId)
    const nonce = new Uint8Array(fromBase64(nonceB64))
    const plaintext = await crypto.subtle.decrypt(
      { name: 'AES-GCM', iv: nonce },
      key,
      fromBase64(ciphertextB64),
    )
    return new TextDecoder().decode(plaintext)
  }

  async function encryptFileForChat(file: File, peerPublicKeyB64: string, chatId: string) {
    const key = await deriveChatKey(peerPublicKeyB64, chatId)
    const nonce = crypto.getRandomValues(new Uint8Array(12))
    const data = await file.arrayBuffer()
    const encrypted = await crypto.subtle.encrypt({ name: 'AES-GCM', iv: nonce }, key, data)

    const encryptedBlob = new Blob([encrypted], { type: 'application/octet-stream' })
    const encryptedFile = new File([encryptedBlob], `${file.name}.enc`, { type: 'application/octet-stream' })

    return {
      encryptedFile,
      fileNonce: toBase64(nonce.buffer),
      version: E2EE_VERSION,
    }
  }

  async function decryptFileForChat(encrypted: Blob, fileNonceB64: string, peerPublicKeyB64: string, chatId: string, mimeType?: string) {
    const key = await deriveChatKey(peerPublicKeyB64, chatId)
    const nonce = new Uint8Array(fromBase64(fileNonceB64))
    const data = await encrypted.arrayBuffer()
    const decrypted = await crypto.subtle.decrypt({ name: 'AES-GCM', iv: nonce }, key, data)
    return new Blob([decrypted], { type: mimeType || 'application/octet-stream' })
  }

  return {
    ensurePublished,
    ensureLocalKeyPair,
    encryptTextForChat,
    decryptTextForChat,
    encryptFileForChat,
    decryptFileForChat,
    version: E2EE_VERSION,
  }
}
import { defineStore } from 'pinia'

export const useChatStore = defineStore('chat', {
  state: () => ({
    chats:    [] as any[],
    messages: [] as any[],
    activeChatId: null as string | null,
    typingUsers: {} as Record<string, ReturnType<typeof setTimeout>>,
  }),
  actions: {
    async loadChats() {
      const headers = useAuthHeaders()
      this.chats = await $fetch('/api/chats', { headers }) as any[] ?? []
    },
    async loadMessages(chatId: string) {
      this.activeChatId = chatId
      const headers = useAuthHeaders()
      this.messages = await $fetch(`/api/chats/${chatId}/messages`, { headers }) as any[] ?? []
    },
    async markAllRead(chatId: string) {
      const headers = useAuthHeaders()
      try {
        const res: any = await $fetch(`/api/chats/${chatId}/read`, { method: 'PUT', headers })
        // Update delete_at for affected messages.
        if (res?.delete_at) {
          this.messages.forEach((m: any) => {
            if (!m.read_at) {
              m.read_at = new Date().toISOString()
              m.delete_at = res.delete_at
            }
          })
        }
      } catch {}
    },
    pushMessage(msg: any) {
      this.messages.push(msg)
      // Update chat last message.
      const chat = this.chats.find(c => c.id === msg.chat_id)
      if (chat) {
        chat.last_message = msg.type === 'text' ? '[encrypted message]' : '[encrypted file]'
        chat.last_message_at = msg.created_at
        chat.unread_count = (chat.unread_count ?? 0) + 1
      }
    },
    applyReadReceipt(chatId: string, deleteAt: string) {
      this.messages.forEach((m: any) => {
        if (m.chat_id === chatId && !m.read_at) {
          m.read_at = new Date().toISOString()
          m.delete_at = deleteAt
        }
      })
    },
    removeMessage(msgId: string) {
      this.messages = this.messages.filter((m: any) => m.id !== msgId)
    },
    setTyping(userId: string) {
      if (this.typingUsers[userId]) clearTimeout(this.typingUsers[userId])
      this.typingUsers[userId] = setTimeout(() => {
        delete this.typingUsers[userId]
      }, 3000) as any
    },
    isTyping(userId: string) {
      return !!this.typingUsers[userId]
    },
  },
})
import { defineStore } from 'pinia'

export const useCallStore = defineStore('call', {
  state: () => ({
    active:       false,
    peerId:       '' as string,
    peerName:     '' as string,
    type:         'video' as 'video' | 'audio',
    incoming:     false,
    incomingOffer: null as RTCSessionDescriptionInit | null,
  }),
  actions: {
    initCall(peerId: string, peerName: string, type: 'video' | 'audio') {
      this.peerId    = peerId
      this.peerName  = peerName
      this.type      = type
      this.incoming  = false
      this.active    = true
    },
    receiveCall(peerId: string, peerName: string, type: 'video' | 'audio', offer: RTCSessionDescriptionInit) {
      this.peerId        = peerId
      this.peerName      = peerName
      this.type          = type
      this.incoming      = true
      this.incomingOffer = offer
      this.active        = true
    },
    endCall() {
      this.active        = false
      this.peerId        = ''
      this.peerName      = ''
      this.incoming      = false
      this.incomingOffer = null
    },
  },
})
// Singleton WebSocket connection shared across the app.
let ws: WebSocket | null = null
let reconnectTimer: ReturnType<typeof setTimeout> | null = null

export function useWebSocket() {
  const auth = useAuthStore()
  const chatStore = useChatStore()
  const callStore = useCallStore()
  const config = useRuntimeConfig()

  function connect() {
    if (!import.meta.client || !auth.token) return
    if (ws && ws.readyState === WebSocket.OPEN) return

    const wsUrl = `${config.public.wsBase}?token=${encodeURIComponent(auth.token)}`
    ws = new WebSocket(wsUrl)

    ws.onopen = () => {
      console.log('[ws] connected')
      if (reconnectTimer) { clearTimeout(reconnectTimer); reconnectTimer = null }
    }

    ws.onmessage = (evt) => {
      try {
        const msg = JSON.parse(evt.data)
        handleMessage(msg)
      } catch {}
    }

    ws.onclose = () => {
      console.log('[ws] disconnected, reconnecting…')
      ws = null
      reconnectTimer = setTimeout(connect, 3000)
    }

    ws.onerror = () => {
      ws?.close()
    }
  }

  function disconnect() {
    if (reconnectTimer) clearTimeout(reconnectTimer)
    ws?.close()
    ws = null
  }

  function sendRaw(data: object) {
    if (ws?.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify(data))
    }
  }

  function sendTyping(receiverId: string, chatId: string) {
    sendRaw({ type: 'typing', receiver_id: receiverId, chat_id: chatId })
  }

  // ── WebSocket event routing ─────────────────────────────────────────────
  function handleMessage(msg: any) {
    switch (msg.type) {
      case 'message':
        if (msg.data) chatStore.pushMessage(JSON.parse(msg.data))
        break

      case 'read':
        if (msg.data) {
          const d = JSON.parse(msg.data)
          chatStore.applyReadReceipt(d.chat_id, d.delete_at)
        }
        break

      case 'message_deleted':
        if (msg.message_id) chatStore.removeMessage(msg.message_id)
        break

      case 'typing':
        chatStore.setTyping(msg.sender_id)
        break

      case 'call_ring':
        if (msg.data) {
          const d = JSON.parse(msg.data)
          callStore.receiveCall(msg.sender_id, d.display_name ?? msg.sender_id, d.type ?? 'video', d.sdp)
        }
        break

      case 'call_answer':
      case 'call_ice':
      case 'call_end':
      case 'call_reject':
        // Forwarded to the WebRTC composable via a custom event bus.
        window.dispatchEvent(new CustomEvent('webrtc-signal', { detail: msg }))
        break
    }
  }

  return { connect, disconnect, sendRaw, sendTyping }
}
export function useAuth() {
  const auth = useAuthStore()
  const router = useRouter()
  const config = useRuntimeConfig()

  async function loginUser(username: string, password: string) {
    const data: any = await $fetch(`${config.public.apiBase}/auth/login`, {
      method: 'POST',
      body: { username, password },
    })
    auth.set(data.token, data.user)
    await useE2EE().ensurePublished()
    return data
  }

  function logout() {
    auth.logout()
    // Disconnect WebSocket.
    useWebSocket().disconnect()
    router.push('/garden')
  }

  return { loginUser, logout }
}

// Convenience composable: returns headers with the Bearer token.
export function useAuthHeaders() {
  const auth = useAuthStore()
  return auth.token ? { Authorization: `Bearer ${auth.token}` } : {}
}
